export interface Subscription {
  unsubscribe(): void;
}

export interface Observable<T> {
  subscribe(handler: (value: T) => void): Subscription;
}

export class PanelWidget {
  constructor(private readonly changes$: Observable<string>) {}

  // Invoked every time the panel list changes.
  subscribeToChanges(): void {
    this.changes$.subscribe((name) => this.render(name));
  }

  private render(name: string): void {
    void name;
  }
}
